#[repr(C)]
pub struct nmod_poly_res_struct {
    pub res: ulong,
    pub lc: ulong,
    pub len0: slong,
    pub len1: slong,
    pub off: slong,
}
impl Default for nmod_poly_res_struct {
    fn default() -> Self {
        let mut s = ::std::mem::MaybeUninit::<Self>::uninit();
        unsafe {
            ::std::ptr::write_bytes(s.as_mut_ptr(), 0, 1);
            s.assume_init()
        }
    }
}
